mbr.copysrc:
     /* =================================================================== */
     /*                                                                     */
     /*  Documentation:                                                     */
     /*                                                                     */
     /*  Utility . . . : LSTJOB                                             */
     /*  Object  . . . : A_INSTALL  (PGM)                                   */
     /*  Source member : A_INSTALL                                          */
     /*  Source type . : CLLE                                               */
     /*  Description   : LSTJOB - Installer                                 */
     /*  Author  . . . : Thomas Raddatz   <thomas.raddatz@tools400.de>      */
     /*                                                                     */
     /* =================================================================== */
     /*                                                                     */
     /*  This software is free software, you can redistribute it and/or     */
     /*  modify it under the terms of the GNU General Public License (GPL)  */
     /*  as published by the Free Software Foundation.                      */
     /*                                                                     */
     /*  See GNU General Public License for details.                        */
     /*          http://www.opensource.org                                  */
     /*          http://www.opensource.org/licenses/gpl-license.html        */
     /*                                                                     */
     /* =================================================================== */
     /*  History:                                                           */
     /*                                                                     */
     /*  Datum       Name           nderung                                 */
     /*  ----------  ------------  ---------------------------------------  */
     /*                                                                     */
     /* =================================================================== */
     /*   >>PRE-COMPILER<<                                                  */
     /*     >>CRTCMD<<    CRTBNDCL  PGM(QTEMP/&OB) +                        */
     /*                             SRCFILE(&SL/&SF) SRCMBR(&SM);           */
     /*     >>IMPORTANT<<                                                   */
     /*       >>PARM<<    OPTION(*EVENTF);                                  */
     /*     >>END-IMPORTANT<<                                               */
     /*     >>EXECUTE<<                                                     */
     /*     >>CMD<<       CALL   PGM(QTEMP/A_INSTALL) +                     */
     /*                          PARM('*CURRENT' '&SF' '&LI' 'NO');         */
     /*     >>CMD<<       DLTPGM PGM(QTEMP/A_INSTALL);                      */
     /*   >>END-PRE-COMPILER<<                                              */
     /* =================================================================== */
             PGM        PARM(&TGTRLS &SRCFILE &TOLIB &CRTTSTPGM)

             DCL        VAR(&TGTRLS   ) TYPE(*CHAR) LEN(10)
             DCL        VAR(&SRCFILE  ) TYPE(*CHAR) LEN(10)
             DCL        VAR(&TOLIB    ) TYPE(*CHAR) LEN(10)
             DCL        VAR(&CRTTSTPGM) TYPE(*CHAR) LEN(10)

             DCL        VAR(&SRCLIB   ) TYPE(*CHAR) LEN(10)

             CHGVAR     VAR(&SRCLIB) VALUE(&TOLIB   )

     /* -------------------------------- */
     /*  Delete old objects              */
     /* -------------------------------- */
             DLTMOD     MODULE(&TOLIB/LSTJOBR1)
             MONMSG     MSGID(CPF2105)

             DLTSRVPGM  SRVPGM(&TOLIB/LSTJOB)
             MONMSG     MSGID(CPF2105)

             DLTMOD     MODULE(&TOLIB/LSTJOB_T1)
             MONMSG     MSGID(CPF2105)

             DLTPGM     PGM(&TOLIB/LSTJOB_T1)
             MONMSG     MSGID(CPF2105)

             DLTMOD     MODULE(&TOLIB/LSTJOB_T2)
             MONMSG     MSGID(CPF2105)

             DLTPGM     PGM(&TOLIB/LSTJOB_T2)
             MONMSG     MSGID(CPF2105)

     /* -------------------------------- */
     /*  Create modules                  */
     /* -------------------------------- */
             CRTRPGMOD  MODULE(&TOLIB/LSTJOBR1) +
                          SRCFILE(&SRCLIB/&SRCFILE) SRCMBR(*MODULE) +
                          DBGVIEW(*LIST) TRUNCNBR(*NO) +
                          TGTRLS(&TGTRLS)
             DLTSPLF    FILE(LSTJOBR1 ) JOB(*) SPLNBR(*LAST)
             MONMSG     MSGID(CPF0000)

     /* -------------------------------- */
     /*  Create service programs         */
     /* -------------------------------- */
             CRTSRVPGM  SRVPGM(&TOLIB/LSTJOB) +
                          MODULE(&TOLIB/LSTJOBR1) +
                          EXPORT(*SRCFILE) +
                          SRCFILE(&SRCLIB/&SRCFILE) +
                          SRCMBR(LSTJOB) +
                          ACTGRP(*CALLER) +
                          DETAIL(*BASIC) +
                          BNDSRVPGM(*LIBL/BASICS1) +
                          TEXT('List Jobs API') +
                          TGTRLS(&TGTRLS)
             DLTSPLF    FILE(LSTJOB) JOB(*) SPLNBR(*LAST)
             MONMSG     MSGID(CPF0000)

     /* -------------------------------- */
     /*  Create test programs            */
     /* -------------------------------- */
             IF         COND(&CRTTSTPGM *EQ 'YES') THEN(DO)
                CRTRPGMOD  MODULE(&TOLIB/LSTJOB_T1) +
                             SRCFILE(&SRCLIB/&SRCFILE) +
                             SRCMBR(*MODULE) +
                             DBGVIEW(*LIST) +
                             TRUNCNBR(*NO) +
                             TGTRLS(&TGTRLS)
                DLTSPLF    FILE(LSTJOB_T1) JOB(*) SPLNBR(*LAST)
                MONMSG     MSGID(CPF0000)

                CRTPGM     PGM(&TOLIB/LSTJOB_T1) +
                             MODULE(*PGM) +
                             BNDSRVPGM(&TOLIB/LSTJOB) +
                             ACTGRP(*NEW) +
                             DETAIL(*BASIC) +
                             TGTRLS(&TGTRLS)
                DLTSPLF    FILE(LSTJOB_T1) JOB(*) SPLNBR(*LAST)
                MONMSG     MSGID(CPF0000)

                DLTMOD    MODULE(&TOLIB/LSTJOB_T1)

                CRTRPGMOD  MODULE(&TOLIB/LSTJOB_T2) +
                             SRCFILE(&SRCLIB/&SRCFILE) +
                             SRCMBR(*MODULE) +
                             DBGVIEW(*LIST) +
                             TRUNCNBR(*NO) +
                             TGTRLS(&TGTRLS)
                DLTSPLF    FILE(LSTJOB_T2) JOB(*) SPLNBR(*LAST)
                MONMSG     MSGID(CPF0000)

                CRTPGM     PGM(&TOLIB/LSTJOB_T2) +
                             MODULE(*PGM) +
                             BNDSRVPGM(&TOLIB/LSTJOB) +
                             ACTGRP(*NEW) +
                             DETAIL(*BASIC) +
                             TGTRLS(&TGTRLS)
                DLTSPLF    FILE(LSTJOB_T2) JOB(*) SPLNBR(*LAST)
                MONMSG     MSGID(CPF0000)

                DLTMOD    MODULE(&TOLIB/LSTJOB_T2)
             ENDDO

     /* -------------------------------- */
     /*  Delete obsolete objects         */
     /* -------------------------------- */
             DLTMOD     MODULE(&TOLIB/LSTJOBR1)

             ENDPGM

**free
/if NOT defined(CEELIB)
/define CEELIB

// ---------------------------------------------------------------
//   Program or Procedure Call APIs
// ---------------------------------------------------------------

//  Condition token, used as feedback code
dcl-ds cee_fc_t qualified template;
  Condition_ID char(4) pos(1);
  MsgSev       int(5) pos(1);
  Msg_No       uns(5) pos(3);
  Flags        char(1) pos(5);
  Facility_ID  char(3) pos(6);
  I_S_Info     char(4) pos(9);
end-ds;

//  Retrieve Operational Descriptor Information (CEEDOD)
dcl-pr CEEDOD extproc('CEEDOD');
  i_posn     int(10) const;
  o_desctype int(10);
  o_datatype int(10);
  o_descinf1 int(10);
  o_descinf2 int(10);
  o_datalen  int(10);
  o_fc       char(12) options(*omit);
end-pr;

//  Reference fields for CEEDOD API
dcl-ds descInf_t template qualified;
  desctype int(10);
  datatype int(10);
  descinf1 int(10);
  descinf2 int(10);
  datalen  int(10);
end-ds;

//  Test for Omitted Argument (CEETSTA) API
dcl-pr CEETSTA extproc('CEETSTA');
  io_isPresent int(10);
  i_argNum     int(10) const;
  o_fc         char(12) options(*omit);
end-pr;

//  Get String Information (CEEGSI) API
dcl-pr CEEGSI extproc('CEEGSI');
  i_posn     int(10) const;
  o_datatype int(10);
  o_curlen   int(10);
  o_maxlen   int(10);
  o_fb       char(12) options(*omit);
end-pr;

//  Reference fields for CEEGSI API
dcl-ds strInf_t template qualified;
  datatype int(10);
  curlen   int(10);
  maxlen   int(10);
end-ds;

// ---------------------------------------------------------------
//   Math APIs
// ---------------------------------------------------------------

//  Logarithm base 10 (double float)
dcl-pr CEESDLG1 extproc('CEESDLG1');
  i_value  float(8) const;
  o_result float(8);
end-pr;

// ---------------------------------------------------------------
//   ILE CEE Date and Time APIs
// ---------------------------------------------------------------

//  Calculate Day of Week from Lilian Date (CEEDYWK) API
dcl-pr CEEDYWK opdesc extproc('CEEDYWK');
  lilian_date int(10) const;
  day_no      int(10);
  feedback    char(12) options(*omit);
end-pr;

//  Convert Lilian Date to Character Format (CEEDATE) API
dcl-pr CEEDATE opdesc extproc('CEEDATE');
  lilian_date int(10) const;
  date_format char(80) options(*varsize) const;
  char_date   char(80) options(*varsize);
  feedback    char(12) options(*omit);
end-pr;

//  Convert Date to Lilian Format (CEEDAYS) API
dcl-pr CEEDAYS opdesc extproc('CEEDAYS');
  char_date   char(80) options(*varsize) const;
  date_format char(80) options(*varsize) const;
  lilian_date int(10);
  feedback    char(12) options(*omit);
end-pr;

//  Convert Seconds to Character Timestamp (CEEDATM) API
dcl-pr CEEDATM opdesc extproc('CEEDATM');
  input_seconds    float(8) const;
  picture_string   char(80) options(*varsize) const;
  output_timestamp char(80) options(*varsize);
  feedback         char(12) options(*omit);
end-pr;

//  Get Offset from Universal Time Coordinated to Local Time (CEEUTCO) API
dcl-pr CEEUTCO extproc('CEEUTCO');
  offsethours   int(10);
  offsetminutes int(10);
  offsetseconds float(8);
  feedback      char(12) options(*nopass);
end-pr;

dcl-ds cee_utco_t qualified template;
  offhours int(10);
  offmins  int(10);
  offsecs  float(8);
end-ds;

//  Convert Timestamp to Number of Seconds (CEESECS) API
dcl-pr CEESECS extproc('CEESECS') opdesc;
  inTimestamp char(255) options(*varsize) const;
  inPicture   char(255) options(*varsize) const;
  outSeconds  float(8);
  outFC       char(12) options(*omit);
end-pr;

// ---------------------------------------------------------------
//   Activation Group and Control Flow APIs
// ---------------------------------------------------------------

//  Register Activation Group Exit Procedure (CEE4RAGE) API
dcl-pr CEE4RAGE extproc('CEE4RAGE');
  i_pProc pointer(*proc) const;
  fc      char(12) options(*omit);
end-pr;

dcl-c END_ACTGRP_CODE_EXCEPTION_MESSAGE x'40000000';
dcl-c END_ACTGRP_CODE_ABNORMAL_END x'00008000';
dcl-c END_ACTGRP_CODE_ACTGRP_IS_ENDING x'00004000';
dcl-c END_ACTGRP_CODE_INIT_BY_RCLACTGRP x'00002000';
dcl-c END_ACTGRP_CODE_INIT_BY_JOB_END x'00001000';
dcl-c END_ACTGRP_CODE_INIT_BY_EXIT_VERB x'00000800';
dcl-c END_ACTGRP_CODE_INIT_BY_FUNCTION_CHECK x'00000400';
dcl-c END_ACTGRP_CODE_INIT_BY_OUT_OF_SCOPE_JUMP x'00000200';

dcl-pr CEE4RAGE_user_exit extproc('CEE4RAGE_user_exit');
  i_ag_mark      uns(10) const;
  i_reason       uns(10) const;
  io_result_code uns(10) const;
  io_user_rc     int(10) const;
end-pr;

//  Register Call Stack Entry Termination User Exit Procedure (CEERTX)
dcl-pr CEERTX extproc('CEERTX');
  i_procPtr  pointer(*proc) const;
  i_rtxToken pointer options(*omit) const;
  o_fc       char(12) options(*omit);
end-pr;

dcl-pr CEERTX_user_exit extproc('CEERTX_user_exit');
  i_rtxToken pointer const;
end-pr;

//  Unregister Call Stack Entry Termination User Exit Procedure (CEEUTX)
dcl-pr CEEUTX extproc('CEEUTX');
  i_procPtr pointer(*proc) const;
  o_fc      char(12) options(*omit);
end-pr;

/endif

**free
/if NOT defined(CLIB)
/define CLIB

//  Basic C data types
/if NOT defined(C_DATA_TYPES)
/define C_DATA_TYPES
// C Data Types
dcl-s char_t char(1) template;
dcl-s short_t int(5) template;
dcl-s ushort_t uns(5) template;
dcl-s int_t int(10) template;
dcl-s uint_t uns(10) template;
dcl-s long_t int(10) template;
dcl-s ulong_t uns(10) template;
dcl-s float_t float(4) template;
dcl-s double_t float(8) template;
/endif

//  stdin, stdout and stderr
dcl-s stdin pointer import('_C_IFS_stdin');
dcl-s stdout pointer import('_C_IFS_stdout');
dcl-s stderr pointer import('_C_IFS_stderr');

//  system -- Execute a Command
//     Return value       Meaning
//     ----------------   --------------------------------------
//     0                  the command is successful
//     -1                 for a NULL pointer
//     1                  the command fails
dcl-pr system int(10) extproc('system');
  i_clCommand pointer options(*string) value;
end-pr;

dcl-s EXCP_MSGID char(7) import('_EXCP_MSGID');

//  time -- Determine Current Time
//     The time() function returns the current calendar time.
//     The return value is also stored in the location that
//     is given by timeptr.
dcl-pr time int(10) extproc('time');
  timeptr pointer value;
end-pr;

//  strftime -- Convert to Formatted Time
//     strftime() returns the number of bytes placed into the
//     array pointed to by 'dest'.
dcl-pr strftime int(10) extproc('strftime');
  dest    pointer value;
  maxsize int(10) value;
  format  pointer options(*string) value;
  timeptr likeds(tm_t) const;
end-pr;

dcl-ds tm_t qualified template;
  tm_sec   int(10);
  tm_min   int(10);
  tm_hour  int(10);
  tm_mday  int(10);
  tm_mon   int(10);
  tm_year  int(10);
  tm_wday  int(10);
  tm_yday  int(10);
  tm_isdst int(10);
end-ds;

//  localtime() -- Correct Local Time, returns tm_t*
//     The localtime() function converts a time value, in
//     seconds, to a structure of type tm.
dcl-pr localtime pointer extproc('localtime');
  time int(10) const;
end-pr;

//  localtime_r() -- Correct Local Time
//     It is the same as localtime() except that it passes
//     in the place to store the returned structure result.
dcl-pr localtime_r pointer extproc('localtime_r');
  time int(10) const;
  tm   likeds(tm_t) const;
end-pr;

//  strtok -- Tokenize String
//     The first time the strtok() function is called, it returns
//     a pointer to the first token in i_string. In later calls
//     it returns a pointer to the next token. A null pointer is
//     returned when there are no more tokens.
dcl-pr strtok pointer extproc('strtok');
  i_string     pointer options(*string) value;
  i_delimiters pointer options(*string) value;
end-pr;

//  atoi -- Convert Character String to Integer
//     The atoi() function returns an int value of the
//     interpreted input string.
dcl-pr atoi int(10) extproc('atoi');
  i_string pointer options(*string) value;
end-pr;

//  memcpy -- Copy Bytes
//     The behavior is undefined if copying takes place
//     between objects that overlap.
//     The memcpy() function returns a pointer to dest.
dcl-pr memcpy pointer extproc('memcpy');
  i_pDest pointer value;
  i_pSrc  pointer value;
  i_count uns(10) value;
end-pr;

//  memset -- Set Bytes to Value
//     The memset() function returns a pointer to dest.
dcl-pr memset pointer extproc('memset');
  i_pDest pointer value;
  i_char  int(10) value;
  i_count uns(10) value;
end-pr;

//  memmove -- Copy Bytes
//     memmove allows copying between objects that may overlap
//     as if src is first copied into a temporary array.
//     The memmove() function returns a pointer to dest.
dcl-pr memmove pointer extproc('memmove');
  pMemDest pointer value;
  pMemSrc  pointer value;
  memSize  like(size_t) value;
end-pr;

//  memcmp -- Compare Buffers
//     Return value       Meaning
//     ----------------   --------------------------------------
//     Less than 0        buf1 less than buf2
//     0                  buf1 identical to buf2
//     Greater than 0     buf1 greater than buf2
dcl-pr memcmp int(10) extproc('memcmp');
  pBuf1 pointer value;
  pBuf2 pointer value;
  count like(size_t) value;
end-pr;

//  memicmp -- Compare Bytes (ignore case)
//     Return value       Meaning
//     ----------------   --------------------------------------
//     Less than 0        buf1 less than buf2
//     0                  buf1 identical to buf2
//     Greater than 0     buf1 greater than buf2
dcl-pr memicmp int(10) extproc('__memicmp');
  pBuf1 pointer value;
  pBuf2 pointer value;
  count uns(10) value;
end-pr;

//  strcmp() -- Compare Strings
//     Return value       Meaning
//     ----------------   --------------------------------------
//     Less than 0        string 1 less than string 2
//     0                  string 1 equivalent to string 2
//     Greater than 0     string 1 greater than string 2
dcl-pr strcmp int(10) extproc('strcmp');
  string1 pointer options(*string) value;
  string2 pointer options(*string) value;
end-pr;

//  strcasecmp() -- Compare Strings without Case Sensitivity
//     Return value       Meaning
//     ----------------   --------------------------------------
//     Less than 0        string 1 less than string 2
//     0                  string 1 equivalent to string 2
//     Greater than 0     string 1 greater than string 2
dcl-pr strcasecmp int(10) extproc('strcasecmp');
  string1 pointer options(*string) value;
  string2 pointer options(*string) value;
end-pr;
/if NOT defined(TESTPTR)
/define TESTPTR

//  Test Pointer (TESTPTR)
dcl-pr testptr int(10) extproc('_TESTPTR');
  i_ptr       pointer value;
  i_test_type int(10) value;
end-pr;

dcl-c cTESTPTR_TYPE_PROCPTR 0;
dcl-c cTESTPTR_NO_OPTIMIZED_PARAMETER_PASSING 0;
dcl-c cTESTPTR_OPTIMIZED_PARAMETER_PASSING 1;

dcl-c cTESTPTR_TYPE_MEMPTR 1;
dcl-c cTESTPTR_NON_TERASPACE 0;
dcl-c cTESTPTR_TERASPACE 1;

dcl-c cTESTPTR_ERROR_NOT_EXIST x'2401';
dcl-c cTESTPTR_ERROR_INVALID x'2402';
dcl-c cTESTPTR_ERROR_OBJECT_DESTROYED x'2202';
/endif

//  malloc() - Reserve Storage Block
dcl-pr TS_malloc pointer extproc('_C_TS_malloc');
  i_size uns(10) value;
end-pr;

//  realloc() - Change Reserved Storage Block Size
dcl-pr TS_realloc pointer extproc('_C_TS_realloc');
  i_pMem pointer value;
  i_size uns(10) value;
end-pr;

//  free() - Release Storage Blocks
dcl-pr TS_free extproc('_C_TS_free');
  i_pMem pointer value;
end-pr;

//  _C_TS_malloc_info() - Determine amount of teraspace memory used
dcl-pr TS_malloc_info int(10) extproc('_C_TS_malloc_info');
  o_c_mallinfo likeds(C_mallinfo_t) const;
  i_size       uns(10) value;
end-pr;

//  _C_TS_malloc_debug() - Determine amount of teraspace memory
//                         used (with optional dumps and verification)
dcl-pr TS_malloc_debug int(10) extproc('_C_TS_malloc_debug');
  i_dump_level uns(10) value;
  i_vrfy_level uns(10) value;
  o_c_mallinfo likeds(C_mallinfo_t) const;
  i_size       uns(10) value;
end-pr;

// The following are possible values for the dump_level parameter
dcl-c C_NO_DUMPS 0;
//  Dumps the _C_mallinfo_t structure:
dcl-c C_DUMP_TOTALS 1;
//  Does a hex dump of all allocated chunks of teraspace storage,
//  this is the entire 512K chunk of storage:
dcl-c C_DUMP_CHUNKS 2;
//  Dumps each of the allocated nodes.
//  There is a node for each malloc performed with the header
//  associated with that malloc:
dcl-c C_DUMP_NODES 3;
//  Dumps the cartesian tree used to keep track of the freed nodes:
dcl-c C_DUMP_TREE 4;
dcl-c C_DUMP_ALL 9999;

//  The following are possible values for the verify_level parameter
dcl-c C_NO_CHECKS 0;
dcl-c C_CHECK_TOTALS 1;
dcl-c C_CHECK_CHUNKS 2;
dcl-c C_CHECK_NODES 3;
dcl-c C_CHECK_TREE 4;
dcl-c C_CHECK_ALL 9998;
//  Will call abort() if verification fails
dcl-c C_CHECK_ALL_AND_ABORT 9999;

// The following structure is used to return information
// from the _C_TS_malloc_info routine.  The fields are:
//   total_bytes        - bytes allocated from system
//                        (high water mark)
//   allocated_bytes    - number of allocated bytes
//   unallocated_bytes  - number of unallocated bytes
//   allocated_blocks   - number of allocated blocks
//   unallocated_blocks - number of unallocated blocks
//   requested_bytes    - bytes actually requested from malloc
//   pad_bytes          - bytes used to pad allocation length
//                        to a multiple of 16
//   overhead_bytes     - bytes used for malloc overhead
dcl-ds C_mallinfo_t qualified template;
  total_bytes        int(20);
  allocated_bytes    int(20);
  unallocated_bytes  int(20);
  allocated_blocks   int(20);
  unallocated_blocks int(20);
  requested_bytes    int(20);
  pad_bytes          int(20);
  overhead_bytes     int(20);
end-ds;

//  malloc -- Reserve Storage Block
dcl-pr malloc pointer extproc('malloc');
  i_size uns(10) value;
end-pr;

//  realloc -- Change Reserved Storage Block Size
dcl-pr realloc pointer extproc('realloc');
  i_pMem pointer value;
  i_size uns(10) value;
end-pr;

//  free -- Release Storage Blocks
dcl-pr free extproc('free');
  i_pMem pointer value;
end-pr;

//  srand -- Set Seed for rand Function   e.g.:   srand(getSeed(*null))
dcl-pr srand extproc('srand');
  i_seed uns(10) value;
end-pr;

//  rand -- Generate Random Number                x = rand()
dcl-pr rand int(10) extproc('rand');
end-pr;

dcl-c RAND_MAX 32767;

//  getSeed -- Get Seed for srand function
dcl-pr getSeed int(10) extproc('time');
  i_timePtr pointer value;
end-pr;

//  strlen -- Determine String Length
dcl-pr strlen uns(10) extproc('strlen');
  i_string pointer value;
end-pr;

//  tmpnam -- Produce Temporary File Name
dcl-pr tmpnam pointer extproc('tmpnam');
  pTmpNme pointer value;
end-pr;

//  _C_IFS_tmpnam -- Produce Temporary File Name for the IFS file system
dcl-pr ifs_tmpnam pointer extproc('_C_IFS_tmpnam');
  fileName pointer value;
end-pr;

dcl-c L_tmpnam 39; // ! <stdio.h>

dcl-c TMP_MAX 32767; // ! <stdio.h>

//  qsort -- Sort Array
dcl-pr qsort pointer extproc('qsort');
  memPtr    pointer value;
  numElem   like(size_t) value;
  width     like(size_t) value;
  pSortFunc pointer(*proc) value;
end-pr;

//  bsearch -- Search Arrays
dcl-pr bsearch pointer extproc('bsearch');
  keyPtr     pointer value;
  memPtr     pointer value;
  numElem    like(size_t) value;
  width      like(size_t) value;
  pSearchFnc pointer(*proc) value;
end-pr;

//  iconv_open()--Code Conversion Allocation API
dcl-pr iconv_open extproc('iconv_open') like(iconv_t);
  i_toCode   pointer value;
  i_fromCode pointer value;
end-pr;

dcl-ds iconv_t qualified template align;
  return_value int(10);
  cd           int(10) dim(12);
end-ds;

dcl-ds iconv_fromcode_t qualified template;
  ibmccsid      char(8);
  ccsid         char(5);
  convAlt       char(3);
  substAlt      char(1);
  shiftStateAlt char(1);
  inpLengthOpt  char(1);
  errOption     char(1);
  reserved      char(12);
end-ds;

dcl-ds iconv_tocode_t qualified template;
  ibmccsid char(8);
  ccsid    char(5);
  reserved char(19);
end-ds;

//  QtqIconvOpen()--Code Conversion Allocation API
dcl-pr QtqIconv_open extproc('QtqIconvOpen') likeds(iconv_t);
  i_toCode   likeds(QtqCode_t) const;
  i_fromCode likeds(QtqCode_t) const;
end-pr;

dcl-ds QtqCode_t qualified template;
  ccsid         int(10);
  conversionA   int(10);
  substitutionA int(10);
  shiftStateA   int(10);
  inpLenOpt     int(10);
  errOptMxdDta  int(10);
  reserved      char(12);
end-ds;

//  iconv()--Code Conversion API
dcl-pr iconv uns(10) extproc('iconv');
  i_cd         likeds(iconv_t) value;
  i_pInBuf     pointer;
  i_inBytLeft  uns(10);
  i_pOutBuf    pointer;
