/if NOT defined(QUSLJOB)
/define QUSLJOB

//  List Job (QUSLJOB) API
dcl-pr QUSLJOB extpgm('QUSLJOB');
  i_qUsrSpc   char(20) const;
  i_format    char(8) const;
  i_qJob      char(26) const;
  i_status    char(10) const;
  io_errCode  char(65535) options(*nopass: *varsize); // optGrp 1
  i_jobType   char(1) options(*nopass) const; // optGrp 2
  i_numFldRtn int(10) options(*nopass) const; //
  i_keyFldRtn int(10) options(*nopass: *varsize) dim(256) const;
  i_hContinue char(48) options(*nopass) const; // optGrp 3
end-pr;

//  Input Parameter Section
dcl-ds QUSLJOB_inpParm_t qualified template;
  qJobSpc    likeds(qJob_t);
  status     char(10);
  qUsrSpc    likeds(qObj_t);
  format     char(8);
  jobType    char(1);
  reserved_1 char(3);
  numFldRtn  int(10);
  keyFldRtn  int(10) dim(256);
  hContinue  char(48);
end-ds;

//  Header Section
dcl-ds QUSLJOB_header_t qualified template;
  qJobUsed  likeds(qJob_t);
  hContinue char(48);
end-ds;

//  JOBL0100 Format
dcl-ds jobl0100_t qualified template;
  job         char(10);
  user        char(10);
  nbr         char(6);
  intJobID    char(16);
  status      char(10);
  type        char(1);
  subType     char(1);
  reserved_01 char(2);
end-ds;

//  JOBL0200 Format
dcl-ds jobl0200_t qualified template;
  job         char(10);
  user        char(10);
  nbr         char(6);
  intJobID    char(16);
  status      char(10);
  type        char(1);
  subType     char(1);
  reserved_01 char(2);
  jobInfSts   char(1);
  reserved_2  char(3);
  numFldRtn   int(10);
end-ds;
// field information                  likeds(jobl0201_t)

//  Field Information of Format JOBL0200
dcl-ds jobl0201_t qualified template;
  length     int(10);
  key        int(10);
  dataType   char(1);
  reserved_1 char(3);
