**free
/if NOT defined(QUSRJOBI)
/define QUSRJOBI

//  Retrieve Job Information (QUSRJOBI) API
dcl-pr QUSRJOBI extpgm('QUSRJOBI');
  o_rcvVar     char(65535) options(*varsize);
  i_rcvVarLen  int(10) const;
  i_format     char(8) const;
  i_qJob       char(26) const;
  i_intJobID   char(16) const;
  io_errCode   char(65535) options(*nopass: *varsize); // OptGrp 1
  i_resPrfStat char(1) options(*nopass) const; // OptGrp 2
end-pr;

//  This format returns basic performance information about a job.
dcl-ds jobi0100_t qualified template;
  bytRet     int(10);
  bytAvl     int(10);
  job        char(10);
  user       char(10);
  nbr        char(6);
  intJobID   char(16);
  status     char(10);
  type       char(1);
  subType    char(1);
  reserved_1 char(2);
  runPty     int(10);
  timeSlice  int(10);
  dftWait    int(10);
  purge      char(10);
end-ds;

//  This format returns information equivalent to that found on the
//  Work with Active Jobs (WRKACTJOB) command.
dcl-ds jobi0200_t qualified template;
  bytRet          int(10);
  bytAvl          int(10);
  job             char(10);
  user            char(10);
  nbr             char(6);
  intJobID        char(16);
  status          char(10);
  type            char(1);
  subType         char(1);
  sbsDName        char(10);
  runPty          int(10);
  sysPoolID       int(10);
  prcTimeUsd      int(10);
  numAuxIORq      int(10);
  numIntTact      int(10);
  rspTimeTot      int(10);
  fncType         char(1);
  fncName         char(10);
  actJobSts       char(4);
  numDBLckW       int(10);
  numIntLckW      int(10);
  numNonDBLckW    int(10);
  timeDBLckW      int(10);
  timeIntLckW     int(10);
  timeNonDBLckW   int(10);
  reserved_01     char(1);
  currSysPoolID   int(10);
  thrdCount       int(10);
  prcUntTmUsd     uns(20);
  numAuxIORqLng   uns(20);
  prcUntTmUsdDB   uns(20);
  pageFaults      uns(20);
  actJobStsJobEnd char(4);
  memPoolName     char(10);
  msgRply         char(1);
end-ds;

//  This format returns job queue and output queue information for a job, as
//  well as information about the submitter's job if the job is a submitted batch job.
dcl-ds jobi0300_t qualified template;
  bytRet     int(10);
  bytAvl     int(10);
  job        char(10);
  user       char(10);
  nbr        char(6);
  intJobID   char(16);
  status     char(10);
  type       char(1);
  subType    char(1);
  jobQ       char(10);
  jobQLib    char(10);
  jobQPty    char(2);
  outQ       char(10);
  outQLib    char(10);
  outQPty    char(2);
  prtDev     char(10);
  sbmJob     char(10);
  sbmUser    char(10);
  sbmNbr     char(6);
  sbmMsgQ    char(10);
  sbmMsgQLib char(10);
  stsOnJobQ  char(10);
  datTimSbm  char(8);
  jobDate    char(7);
end-ds;

//  This format primarily returns job attribute types of information.
dcl-ds jobi0400_t qualified template;
  bytRet        int(10);
  bytAvl        int(10);
  job           char(10);
  user          char(10);
  nbr           char(6);
  intJobID      char(16);
  status        char(10);
  type          char(1);
  subType       char(1);
