  brkMsgHdl     char(10);
  stsMsgHdl     char(10);
  devRcvrAct    char(13);
  ddmCnvHdl     char(10);
  dateSep       char(1);
  dateFmt       char(4);
  prtText       char(30);
  sbmJob        char(10);
  sbmUser       char(10);
  sbmNbr        char(6);
  sbmMsgQ       char(10);
  sbmMsgQLib    char(10);
  timeSep       char(1);
  ccsid         int(10);
  dateTimeScd   char(8);
  prtKeyFmt     char(10);
  sortSeq       char(10);
  sortSeqLib    char(10);
  langID        char(3);
  countryID     char(2);
  complSts      char(1);
