end-ds;

//  This format returns information about active jobs only.
//  It is intended to supplement the JOBI0400 format.
dcl-ds jobi0600_t qualified template;
  bytRet      int(10);
  bytAvl      int(10);
  job         char(10);
  user        char(10);
  nbr         char(6);
  intJobID    char(16);
  status      char(10);
  type        char(1);
  subType     char(1);
  jobSws      char(8);
  endStatus   char(1);
  sbsD        char(10);
  sbsDLib     char(10);
  curUser     char(10);
  dbcs        char(1);
  exitKey     char(1);
  cancelKey   char(1);
  prdRetCode  int(10);
  userRetCode int(10);
  pgmretCode  int(10);
  spcEnv      char(10);
  device      char(10);
  grpPrf      char(10);
  grpPrfAry   char(10) dim(15);
  jobUsrID    char(10);
  jobUsrIDStg char(1);
end-ds;

//  This format returns library list information for an active job.
dcl-ds jobi0700_t qualified template;
  bytRet     int(10);
  bytAvl     int(10);
  job        char(10);
  user       char(10);
  nbr        char(6);
  intJobID   char(16);
  status     char(10);
  type       char(1);
  subType    char(1);
  reserved_1 char(2);
  numSysLibE int(10);
  numPrdLibE int(10);
